import { useEffect, useState } from "react";
import axios from "../api/axios";
import { useNavigate } from "react-router-dom";

export default function AdminDashboard() {
  const [stats, setStats] = useState({ totalBookings: 0, activeBookings: 0, totalSlots: 0, revenue: 0, totalUsers: 0 });
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchAdminData = async () => {
      try {
        const role = localStorage.getItem("role");
        if (role !== "admin") {
          navigate("/");
          return;
        }

        const statsRes = await axios.get("/admin/stats");
        setStats(statsRes.data);

        const bookingsRes = await axios.get("/admin/bookings");
        setBookings(bookingsRes.data);

        setLoading(false);
      } catch (err) {
        console.error("Admin Access Error", err);
        navigate("/");
      }
    };
    fetchAdminData();
  }, [navigate]);

  if (loading) return <div style={{ textAlign: "center", marginTop: "50px" }}>Loading Admin Dashboard...</div>;

  return (
    <div style={{ animation: "fadeIn 0.5s ease-out" }}>
      <div style={{ display: "flex", alignItems: "center", gap: "12px", marginBottom: "32px", borderBottom: "1px solid var(--border-subtle)", paddingBottom: "20px" }}>
          <div style={{ background: "var(--accent-primary)", color: "white", padding: "12px", borderRadius: "12px", display: "flex", alignItems: "center", justifyContent: "center" }}>
              <i className="fa-solid fa-shield-halved fa-2x"></i>
          </div>
          <div>
              <h1 style={{ color: "var(--text-primary)", margin: 0, fontSize: "2rem", fontWeight: "800" }}>Admin Dashboard</h1>
              <p style={{ color: "var(--text-secondary)", margin: 0, fontSize: "1rem" }}>System overview and management</p>
          </div>
      </div>

      {/* Stats Grid */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", gap: "24px", marginBottom: "40px" }}>
        <StatCard title="Total Users" value={stats.totalUsers} icon="fa-users" color="var(--accent-primary)" />
        <StatCard title="Active Bookings" value={stats.activeBookings} icon="fa-car" color="var(--status-success)" />
        <StatCard title="Total Slots" value={stats.totalSlots} icon="fa-square-parking" color="var(--status-warning)" />
        <StatCard title="Total Revenue" value={`$${stats.revenue || 0}`} icon="fa-sack-dollar" color="var(--status-danger)" />
      </div>

      {/* Bookings Table */}
      <h2 style={{ marginTop: "10px", color: "var(--text-primary)", fontSize: "1.5rem", display: "flex", alignItems: "center", gap: "8px" }}>
          <i className="fa-solid fa-clock-rotate-left" style={{ color: "var(--text-muted)" }}></i> Recent Bookings
      </h2>
      <div style={{ overflowX: "auto", background: "white", borderRadius: "10px", boxShadow: "0 4px 10px rgba(0,0,0,0.05)" }}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "#f8f9fa", textAlign: "left" }}>
              <th style={thStyle}>User</th>
              <th style={thStyle}>Vehicle</th>
              <th style={thStyle}>Location</th>
              <th style={thStyle}>Slot</th>
              <th style={thStyle}>Time</th>
              <th style={thStyle}>Status</th>
            </tr>
          </thead>
          <tbody>
            {bookings.map(b => (
              <tr key={b._id} style={{ borderBottom: "1px solid #eee" }}>
                <td style={tdStyle}>
                  <div>{b.userId?.name || "Unknown"}</div>
                  <div style={{ fontSize: "0.8em", color: "#888" }}>{b.userId?.email}</div>
                </td>
                <td style={tdStyle}>{b.vehicleNumber || "N/A"}</td>
                <td style={tdStyle}>{b.slotId?.parkingLotId?.name || "Unknown"}</td>
                <td style={tdStyle}>{b.slotId?.slotNumber || "N/A"}</td>
                <td style={tdStyle}>
                  <div>{new Date(b.startTime).toLocaleDateString()}</div>
                  <div style={{ fontSize: "0.8em", color: "#888" }}>{new Date(b.startTime).toLocaleTimeString()} - {new Date(b.endTime).toLocaleTimeString()}</div>
                </td>
                <td style={tdStyle}>
                  <span style={{
                    padding: "6px 12px", borderRadius: "20px", fontSize: "0.75rem", fontWeight: "700", display: "inline-block",
                    background: b.status === "Booked" || b.status === "Active" ? "var(--status-success-bg)" : "var(--status-danger-bg)",
                    color: b.status === "Booked" || b.status === "Active" ? "var(--status-success)" : "var(--status-danger)"
                  }}>
                    {b.status.toUpperCase()}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

const StatCard = ({ title, value, icon, color }) => (
  <div style={{ background: "var(--bg-secondary)", padding: "24px", borderRadius: "var(--radius-lg)", boxShadow: "var(--shadow-md)", border: "1px solid var(--border-subtle)", position: "relative", overflow: "hidden", transition: "transform 0.2s ease", cursor: "default" }} onMouseOver={e => e.currentTarget.style.transform = "translateY(-5px)"} onMouseOut={e => e.currentTarget.style.transform = "translateY(0)"}>
    <div style={{ position: "absolute", right: "-10px", top: "-10px", opacity: 0.05, fontSize: "6rem", color: color }}>
        <i className={`fa-solid ${icon}`}></i>
    </div>
    <div style={{ color: "var(--text-secondary)", fontSize: "0.95rem", fontWeight: "600", textTransform: "uppercase", letterSpacing: "0.5px", marginBottom: "8px", display: "flex", alignItems: "center", gap: "8px" }}>
        <i className={`fa-solid ${icon}`} style={{ color: color }}></i> {title}
    </div>
    <div style={{ fontSize: "2.5rem", fontWeight: "800", color: "var(--text-primary)", letterSpacing: "-1px" }}>{value}</div>
  </div>
);

const thStyle = { padding: "16px 20px", color: "var(--text-secondary)", fontSize: "0.85rem", textTransform: "uppercase", fontWeight: "700", borderBottom: "2px solid var(--border-subtle)" };
const tdStyle = { padding: "16px 20px", color: "var(--text-primary)", borderBottom: "1px solid var(--border-subtle)", fontSize: "0.95rem" };
